enum State {
    Init,
    DoTask1(Task1),
    DoTask2(Task2),
    Done,
}

struct Plan {
    state: State,
}

impl Plan {
    fn update(&mut self) -> bool {
        use State::*;
        match self.state {
            Init => {
                println!("Init");
                self.state = DoTask1(Task1 {});
            }
            DoTask1(ref task) => {
                println!("Task1");
                task.foo();

                self.state = DoTask2(Task2 { count : 3 });
            }            
            DoTask2(ref mut task) => {
                println!("Task2");
                if task.bar() == false {
                    self.state = Done;
                }
            }
            Done => {
                println!("Done");
                return false;
            }
        }
        true
    }
}

struct Task1 {}
impl Task1 {
    fn foo(&self) {
        println!("- hello");
    }
}

struct Task2 {
    count: u32,
}
impl Task2 {
    fn bar(&mut self) -> bool {
        if self.count > 0 {
            println!("- world");
            self.count -= 1;
            true
        } else {
            false
        }
    }
}

fn main() {
    let mut plan = Plan { state: State::Init };
    while plan.update() {    }
}

struct Actor {
    id: u64,
    count: u64,
}

impl Actor {
    fn new(id: u64) -> Self {
        Self { id, count: 0 }
    }

    fn do_something(&mut self, others: &[Box<Actor>]) {
        for other in others {
            println!("Examining {} -> {}", self.id, other.id);
        }

        self.count += 1;
        println!("Actor {} has count {}", self.id, self.count);
    }
}

struct World {
    actors: Vec<Box<Actor>>,
}

fn main() {
    let mut world = World { actors: Vec::new() };

    for i in 0..5 {
        world.actors.push(Box::new(Actor::new(i)));
    }

    if let Some((current, rest)) = world.actors.split_first_mut() {
        let mut i = 0;
        while i < rest.len() {
            current.do_something(rest);
            std::mem::swap(current, &mut rest[i]);
            i += 1;
        }
    }
}

