import React from 'react';
import _ from 'lodash';

function Outer({
    database,
    children,
}) {
    const handleClickRandom = (evt) => {
        evt.preventDefault();
        const page = _.shuffle(database.pages)[0];
        const href = page.href;
        history.pushState(null, '', href);
    };

    const sections = [
        [ '/', 'Home' ],
        [ '/blog', 'Blog' ],
        [ '/products', 'Products' ],
        [ '/licensing', 'Licensing' ],
        [ '/about', 'About' ],
    ]

    return (
        <div>
            <div className="site-layout">
                <div
                    className="site-header"
                    style={{
                        display: 'flex',
                        flexDirection: 'row',
                        minWidth: '80rem',
                        maxWidth: '80rem',
                        margin: '0 auto',
                    }}>
                    <div                    
                        style={{
                            display: 'flex',
                            flexDirection: 'row',
                            flexGrow: 0,
                        }}>
                        <a href="https://blacklivesmatter.com/" style={{ textDecoration: 'none' }}>🖤</a>
                        {sections.map(([url, name ]) => (
                            <React.Fragment key={name}>
                                <div style={{ width : '1.5rem' }} />
                                <a style={{ flexGrow: 0 }} href={url}>{name}</a>
                            </React.Fragment>
                        ))}
                    </div>
                    <div style={{ flexGrow: 8 }} />
                    <div                    
                        style={{
                            display: 'flex',
                            flexDirection: 'row',
                            flexGrow: 0,
                        }}>
                        <a style={{ flexGrow: 0 }} href="/page_index">Index</a>
                        <div style={{ width : '1.5rem' }} />
                        <a style={{ flexGrow: 0 }} href="#" onClick={handleClickRandom}>Random!</a>
                    </div>
                </div>
            </div>
            <div style={{
                display: 'flex',
                flexDirection: 'column',
                minHeight: 'calc(100vh - 120px)'
            }}
            >
                {children}
            </div>
            <div className="site-footer">
                <div>
                    Twitter: <a href="https://twitter.com/RidleyWinters">RidleyWinters</a>
                </div>
                <div>
                    Favicon designed by
                    {' '}<a href="https://www.flaticon.com/authors/good-ware">Good Ware</a>{' '}
                    available at
                    {' '}<a href="https://www.flaticon.com/free-icon/woodland_2933738?term=landscape&page=1&position=">flaticon</a>.
                </div>
            </div>
        </div>
    );
}

export default function PageLayout({
    database,
    page,
    children,
}) {
    console.log(page);

    const pageWidth = page.properties.page_width || '80rem';

    return (
        <Outer database={database}>
            <div
                style={{
                    display: 'flex',
                    flexDirection: 'column',
                    flexGrow: 1,
                    margin: '0 auto 6rem',
                    minWidth: pageWidth,
                    maxWidth: pageWidth,
                }}
            >
                <div
                    className="page-content"
                    style={{
                        flexGrow: 1,
                    }}
                >
                    {children}
                </div>
            </div>
        </Outer>
    );
}

