import _ from 'lodash';

function addStylesheets(stylesheets) {
    _.each(stylesheets, (href) => {
        const link = document.createElement('link');
        link.type = 'text/css';
        link.rel = "stylesheet";
        link.href = href;
        document.head.appendChild(link);
    });
}

function addStyleNode(style) {
    const lines = [];
    for (let selector in style) {
        const props = style[selector];
        lines.push(`${selector} {`);
        for (let javascriptName in props) {
            const cssName = javascriptName.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`);
            lines.push(`    ${cssName}: ${props[javascriptName]};`);
        }
        lines.push(`}`);
    }

    const el = document.createElement('style');
    el.type = 'text/css';
    el.appendChild(document.createTextNode(lines.join('\n')));
    document.head.appendChild(el);
}

function addStyleNodePrefix(prefix, style) {

    const remapped = {};
    const keys = Object.keys(style);
    keys.forEach((key) => {
        const k = key.split(',').map((p) => `${prefix} ${p}`).join(', ');
        remapped[k] = style[key];
    });
    addStyleNode(remapped);
}

function addScriptNode(url) {
    const el = document.createElement('script');
    el.src = url;
    document.body.appendChild(el);
}

let runCount = 0;
let chroma = null;

export default function SiteLayout({ children }) {
    if (runCount === 0) {
        runCount++;

        addScriptNode('https://cdnjs.cloudflare.com/ajax/libs/chroma-js/2.1.0/chroma.min.js');

        addStylesheets([
            "https://fonts.googleapis.com/css?family=Catamaran:100,200,300,400,500,600,700,800,900&display=swap&subset=latin-ext",
            "https://fonts.googleapis.com/css?family=Faustina&display=swap",
            "https://fonts.googleapis.com/css?family=Courier+Prime&display=swap",
        ]);

        // Hacky loop to make sure external script is loaded
        document.body.style.opacity = 0.0;
        const checkReady = () => {
            if (!window.chroma) {
                setTimeout(checkReady, 200);
                return;
            }
            chroma = window.chroma;
            document.body.style.opacity = 1.0;

            // TODO: how can these be shared as a theme object?
            const colors = {};
            colors.base = ["fe5f55", "2391cc", "313e50", "5d8f68", "07393c"].map((c) => chroma(`#${c}`));
            colors.header = colors.base[3];
            colors.link = colors.base[1];

            colors.red = colors.base[0];
            colors.blue = colors.base[1];
            colors.darkblue = colors.base[2];
            colors.green = colors.base[3];
            colors.darkgreen = colors.base[4];

            addStyleNode({
                "body, input, button": {
                    fontFamily: 'Catamaran',
                },
                "a, a:visited": {
                    color: 'rgb(31, 136, 180)',
                    textDecoration: 'none',
                },
                "code": {
                    fontSize: '0.85em',
                    'color': colors.green.mix('black', 0.5).css(),
                },
                "a code": {
                    color: 'rgb(31, 136, 180)',
                },
                "body": {
                    fontFamily: 'Catamaran',
                },
                ".t-sans": {
                    fontFamily: 'Catamaran',
                },
                ".t-serif": {
                    fontFamily: 'Faustina'
                },
                ".t-mono": {
                    fontFamily: 'Courier Prime',
                },

                '.site-layout': {
                    padding: '12px 2rem 6px',
                    backgroundColor: colors.link.mix('black', 0.5).css(),
                    boxShadow: "2px 2px 6px 2px rgba(0,0,0,0.09)",
                },
                '.mermaid' : {
                    fontSize : '20%',
                }

            });

            addStyleNodePrefix('.site-header', {
                "" : {
                },
                "a, a:visited": {
                    'color': colors.link.mix('white', 0.8).css(),
                },
                "a:hover": {
                    'color': colors.base[0].css(),
                },
            });

            addStyleNodePrefix('.site-footer', {
                "": {
                    minHeight: '120px',
                    padding: '32px 2rem 6px',
                    backgroundColor: colors.link.mix('black', 0.5).css(),
                    color: 'white',
                    fontSize: '90%',
                },
                "a, a:visited": {
                    color: colors.blue.mix('white', 0.15).css(),
                },
                "a:hover": {
                    'color': colors.base[0].css(),
                },
            })

            addStyleNodePrefix('.page-content', {
                "": {
                    marginTop: '1rem',
                    fontSize: '110%',
                    color : '#333',
                },
                "a, a:visited": {
                    'color': colors.link.css(),
                },
                "a:hover": {
                    'color': colors.base[0].css(),
                },

                "h1": {
                    fontSize: '2.5rem',
                    'color': colors.link.mix('black', 0.6).css(),
                },
                "h2": { fontSize: '2rem', letterSpacing: '0.05rem', fontWeight: 300 },
                "h3": { fontSize: '1.45rem', letterSpacing: '0.05rem', fontWeight: 300 },
                "h4": {
                    fontSize: '1.15rem', letterSpacing: '0.05rem', fontWeight: 300,
                    'color': colors.darkgreen.mix('black', 1.0).css(),
                },
                "h5": {
                    fontSize: '1.1rem', 
                    padding: 0,
                    margin: '1.5rem 0 0.5rem',
                    fontWeight: 500,
                    'color': colors.darkgreen.mix('white', 0.25).css(),
                },
                "h2,h3": {
                    'color': colors.link.mix('black', 0.5).css(),
                },
            })
        };
        checkReady();
    }

    return children;
}

